using System.Collections.Generic;
public static class Solution {
  public static Dictionary<string,int> Solve(string[] arr) {
    var m = new Dictionary<string,int>();
    foreach (var x in arr) {
      if (!m.ContainsKey(x)) m[x] = 0;
      m[x] += 1;
    }
    return m;
  }
}

