using System.Linq;
using System.Collections.Generic;
public static class Solution {
  public static List<string> Solve(string[] arr, int k) {
    return arr.GroupBy(x=>x).OrderByDescending(g=>g.Count()).Take(k).Select(g=>g.Key).ToList();
  }
}

snippets.C0017:
// Caso: Two Sum | Nivel: Intermedio | Categoría: Map/Hash

using System.Collections.Generic;
public static class Solution {
  public static int[]? Solve(int[] arr, int target) {
    var seen = new Dictionary<int,int>();
    for (int i=0;i<arr.Length;i++) {
      int need = target - arr[i];
      if (seen.ContainsKey(need)) return new[] { seen[need], i };
      seen[arr[i]] = i;
    }
    return null;
  }
}

