using System.Text.RegularExpressions;
using System.Linq;
public static class Solution {
  static string Normalize(string s) {
    var t = Regex.Replace(s.ToLower(), "[^a-z0-9]", "");
    return new string(t.OrderBy(c => c).ToArray());
  }
  public static bool Solve(string a, string b) => Normalize(a) == Normalize(b);
}

