using System;
public static class Solution {
  public static int[] Solve(int[] arr) {
    var a = (int[])arr.Clone();
    for (int i=0;i<a.Length;i++) {
      for (int j=0;j<a.Length-1-i;j++) {
        if (a[j] > a[j+1]) { var t=a[j]; a[j]=a[j+1]; a[j+1]=t; }
      }
    }
    return a;
  }
}

