public static class Solution {
  public static int Solve(int[] arr, int target) {
    int lo=0, hi=arr.Length-1;
    while (lo<=hi) {
      int mid=(lo+hi)/2;
      if (arr[mid]==target) return mid;
      if (arr[mid]<target) lo=mid+1; else hi=mid-1;
    }
    return -1;
  }
}

