snippets.C0646:
// Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
using System;

public static class Solution {
  public static bool Solve(string rut) {
    var clean = (rut ?? "")
      .Replace(".", "")
      .Replace("-", "")
      .Replace(" ", "")
      .ToUpperInvariant();

    if (clean.Length < 2) return false;

    var body = clean.Substring(0, clean.Length - 1);
    var dv = clean[^1];

    foreach (var ch in body) if (!char.IsDigit(ch)) return false;

    int sum = 0, mul = 2;
    for (int i = body.Length - 1; i >= 0; i--) {
      int d = body[i] - '0';
      sum += d * mul;
      mul = (mul == 7) ? 2 : (mul + 1);
    }

    int mod = 11 - (sum % 11);
    char dvCalc = mod == 11 ? '0' : mod == 10 ? 'K' : (char)('0' + mod);
    return dv == dvCalc;
  }
}

