// C0666 · Merge sort (Intermedio, Algoritmos)
public static int[] Solve(int[] arr){
  if(arr.Length<=1) return arr;
  int mid = arr.Length/2;
  int[] left = arr[..mid];
  int[] right= arr[mid..];
  left = Solve(left); right = Solve(right);
  var outp = new int[arr.Length];
  int i=0,j=0,k=0;
  while(i<left.Length && j<right.Length){
    outp[k++] = (left[i] <= right[j]) ? left[i++] : right[j++];
  }
  while(i<left.Length) outp[k++] = left[i++];
  while(j<right.Length) outp[k++] = right[j++];
  return outp;
}

snippets.C0669:
// C0669 · LRU cache (Intermedio, Algoritmos)
using System.Collections.Generic;

public class LRU<K,V> {
  private readonly int cap;
  private readonly LinkedList<K> order = new();
  private readonly Dictionary<K, (V val, LinkedListNode<K> node)> map = new();

  public LRU(int cap){ this.cap = cap; }

  public V? Get(K key){
    if(!map.TryGetValue(key, out var e)) return default;
    order.Remove(e.node);
    order.AddLast(e.node);
    return e.val;
  }

  public void Put(K key, V val){
    if(map.TryGetValue(key, out var e)){
      order.Remove(e.node);
      order.AddLast(e.node);
      map[key] = (val, e.node);
      return;
    }
    var node = order.AddLast(key);
    map[key] = (val, node);
    if(map.Count > cap){
      var oldest = order.First!.Value;
      order.RemoveFirst();
      map.Remove(oldest);
    }
  }
}

