snippets.C0680:
// C0680 · Uso de teclado (keydown/atajos) (Intermedio, UI/Entrada)
// C# Console.ReadKey (sin Enter)
using System;

public static class Solution {
  public static void Solve() {
    Console.WriteLine("Presiona WASD (q para salir).");
    while (true) {
      var k = Console.ReadKey(intercept: true);
      var ch = char.ToLowerInvariant(k.KeyChar);
      if (ch == 'q') break;
      if (ch == 'w') Console.WriteLine("Mover: arriba");
      if (ch == 's') Console.WriteLine("Mover: abajo");
      if (ch == 'a') Console.WriteLine("Mover: izquierda");
      if (ch == 'd') Console.WriteLine("Mover: derecha");
    }
  }
}

