snippets.C0683:
// C0683 · Routing básico GET (HTML)
// C# (sin ASP.NET Core): HttpListener (demo)
using System;
using System.Net;
using System.Text;

var listener = new HttpListener();
var port = Environment.GetEnvironmentVariable("PORT") ?? "3000";
listener.Prefixes.Add($"http://localhost:{port}/");
listener.Start();
Console.WriteLine($"Listening on http://localhost:{port}/");

while (true)
{
  var ctx = await listener.GetContextAsync();
  if (ctx.Request.HttpMethod == "GET" && ctx.Request.Url!.AbsolutePath == "/hola")
  {
    var bytes = Encoding.UTF8.GetBytes("<h1>Hola</h1><p>HTML simple</p>");
    ctx.Response.ContentType = "text/html; charset=utf-8";
    ctx.Response.StatusCode = 200;
    await ctx.Response.OutputStream.WriteAsync(bytes);
    ctx.Response.Close();
    continue;
  }
  ctx.Response.StatusCode = 404;
  ctx.Response.Close();
}

snippets.C0700:
// C0700 · Health check /ready /live
// C# (sin ASP.NET Core): HttpListener (demo)
using System;
using System.Net;
using System.Text;

var listener = new HttpListener();
var port = Environment.GetEnvironmentVariable("PORT") ?? "3000";
listener.Prefixes.Add($"http://localhost:{port}/");
listener.Start();
Console.WriteLine($"Listening on http://localhost:{port}/");

while (true)
{
  var ctx = await listener.GetContextAsync();
  if (ctx.Request.HttpMethod == "GET" && ctx.Request.Url!.AbsolutePath == "/live")
  {
    var bytes = Encoding.UTF8.GetBytes("OK");
    ctx.Response.ContentType = "text/plain; charset=utf-8";
    ctx.Response.StatusCode = 200;
    await ctx.Response.OutputStream.WriteAsync(bytes);
    ctx.Response.Close();
    continue;
  }
  ctx.Response.StatusCode = 404;
  ctx.Response.Close();
}

